import Foundation

enum APIError: Error {
    case invalidURL
    case invalidResponse
}

final class APIClient {
    static let shared = APIClient()

    private let session: URLSession

    private init() {
        let configuration = URLSessionConfiguration.default
        configuration.waitsForConnectivity = true
        configuration.timeoutIntervalForRequest = 30
        configuration.timeoutIntervalForResource = 60
        self.session = URLSession(configuration: configuration)
    }

    func fetchPublicAPI(completion: @escaping (Result<String, Error>) -> Void) {
        guard let url = URL(string: "https://api.example.com/status") else {
            completion(.failure(APIError.invalidURL))
            return
        }

        session.dataTask(with: url) { data, response, error in
            if let error {
                completion(.failure(error))
                return
            }

            guard let httpResponse = response as? HTTPURLResponse, 200..<300 ~= httpResponse.statusCode else {
                completion(.failure(APIError.invalidResponse))
                return
            }

            let body = data.flatMap { String(data: $0, encoding: .utf8) } ?? "No content"
            completion(.success(body))
        }.resume()
    }

    func fetchLegacySystem(completion: @escaping (Result<String, Error>) -> Void) {
        guard let url = URL(string: "http://legacy.internal/status") else {
            completion(.failure(APIError.invalidURL))
            return
        }

        session.dataTask(with: url) { data, response, error in
            if let error {
                completion(.failure(error))
                return
            }

            guard let httpResponse = response as? HTTPURLResponse, 200..<300 ~= httpResponse.statusCode else {
                completion(.failure(APIError.invalidResponse))
                return
            }

            let body = data.flatMap { String(data: $0, encoding: .utf8) } ?? "No content"
            completion(.success(body))
        }.resume()
    }
}

import SwiftUI

struct ContentView: View {
    @State private var apiResponse = "Loading secure API..."
    @State private var legacyResponse = "Loading legacy system..."

    var body: some View {
        NavigationView {
            List {
                Section("Secure API") {
                    Text(apiResponse)
                        .textSelection(.enabled)
                }

                Section("Legacy System") {
                    Text(legacyResponse)
                        .textSelection(.enabled)
                }

                Section {
                    Button("Reload") {
                        loadData()
                    }
                }
            }
            .navigationTitle("Connectivity")
            .onAppear {
                loadData()
            }
        }
    }

    private func loadData() {
        APIClient.shared.fetchPublicAPI { result in
            DispatchQueue.main.async {
                switch result {
                case .success(let value):
                    apiResponse = value
                case .failure(let error):
                    apiResponse = "Error: \(error.localizedDescription)"
                }
            }
        }

        APIClient.shared.fetchLegacySystem { result in
            DispatchQueue.main.async {
                switch result {
                case .success(let value):
                    legacyResponse = value
                case .failure(let error):
                    legacyResponse = "Error: \(error.localizedDescription)"
                }
            }
        }
    }
